window.BOSS_QUESTIONS = {"fundament": [{"q": "Inwestujesz 1000 zł na 3 lata przy rocznej stopie 5% i kapitalizacji rocznej. Jaka jest wartość przyszła (FV) tej kwoty?", "options": ["1150,00 zł", "1157,63 zł", "1050,00 zł", "1276,28 zł"], "correct": 1, "explain": "FV = PV·(1+r)ⁿ = 1000·(1,05)³ = 1157,63 zł. Odsetki naliczają się składanie (procent składany), a nie liniowo."}, {"q": "Która z poniższych wielkości wyraża dzisiejszą wartość przepływu pieniężnego oczekiwanego w przyszłości?", "options": ["Wartość przyszła (FV)", "Wartość zaktualizowana / bieżąca (PV)", "Stopa zwrotu z aktywów (ROA)", "Marża zysku brutto"], "correct": 1, "explain": "PV (present value) to dzisiejsza wartość przyszłego przepływu po zdyskontowaniu stopą r: PV = FV / (1+r)ⁿ. FV jest pojęciem odwrotnym (wartość w przyszłości)."}, {"q": "Projekt wymaga nakładu 1000 zł i przynosi po 600 zł na koniec roku 1. i 2. Przy stopie dyskontowej 10% NPV wynosi w przybliżeniu +41 zł. Jaka jest poprawna decyzja inwestycyjna i jej uzasadnienie?", "options": ["Odrzucić, bo suma wpływów (1200 zł) jest tylko nieznacznie większa niż nakład", "Przyjąć, ponieważ NPV jest większe niż zero (większe niż 0)", "Odrzucić, ponieważ IRR jest mniejsze niż 10%", "Wstrzymać się, bo NPV dodatnie nie przesądza o opłacalności"], "correct": 1, "explain": "Reguła NPV: przyjmujemy projekt, gdy NPV jest większe niż 0. Dodatnie NPV (+41 zł) oznacza, że projekt zwiększa wartość firmy, a IRR jest tu większe niż stopa 10%."}, {"q": "Spółka finansuje się w 60% kapitałem własnym (koszt 12%) i 40% długiem (koszt 8%); stawka podatku to 20%. Ile wynosi WACC?", "options": ["10,40%", "9,76%", "10,00%", "8,64%"], "correct": 1, "explain": "WACC = E·rₑ + D·r_d·(1−T) = 0,6·12% + 0,4·8%·(1−0,2) = 7,2% + 2,56% = 9,76%. Koszt długu uwzględnia tarczę podatkową (1−T)."}, {"q": "Zgodnie z modelem CAPM: stopa wolna od ryzyka 3%, współczynnik β akcji = 1,5, premia za ryzyko rynkowe 5%. Jaki jest oczekiwany koszt kapitału własnego?", "options": ["8,0%", "10,5%", "11,0%", "7,5%"], "correct": 1, "explain": "CAPM: rₑ = r_f + β·(r_m − r_f) = 3% + 1,5·5% = 3% + 7,5% = 10,5%. β mierzy ryzyko systematyczne (rynkowe) akcji względem rynku."}, {"q": "Inwestor wybiera między dwoma obligacjami o tej samej oczekiwanej stopie zwrotu, ale różnym odchyleniu standardowym zwrotów. Jak zachowa się inwestor o awersji do ryzyka?", "options": ["Wybierze obligację o wyższym odchyleniu standardowym, licząc na wyższy zysk", "Wybierze obligację o niższym odchyleniu standardowym", "Będzie obojętny, bo oczekiwane zwroty są równe", "Wybierze tę o wyższym β, bo zwykle daje wyższy zwrot"], "correct": 1, "explain": "Przy równym oczekiwanym zwrocie inwestor z awersją do ryzyka preferuje aktywo o niższym ryzyku (niższym odchyleniu standardowym). To istota relacji ryzyko–zwrot."}, {"q": "Które równanie stanowi podstawowe równanie bilansowe w rachunkowości?", "options": ["Aktywa = Kapitał własny − Zobowiązania", "Aktywa = Zobowiązania + Kapitał własny", "Przychody − Koszty = Aktywa", "Aktywa + Zobowiązania = Kapitał własny"], "correct": 1, "explain": "Podstawowe równanie bilansowe: Aktywa = Zobowiązania + Kapitał własny. Suma aktywów (majątku) zawsze równa się sumie źródeł jego finansowania (pasywom)."}, {"q": "Spółka ma aktywa obrotowe 300 tys. zł (w tym zapasy 100 tys.) oraz zobowiązania krótkoterminowe 100 tys. zł. Ile wynosi wskaźnik płynności szybkiej (quick ratio / wskaźnik wyższej płynności)?", "options": ["3,0", "2,0", "1,0", "0,33"], "correct": 1, "explain": "Quick ratio = (aktywa obrotowe − zapasy) / zobowiązania krótkoterminowe = (300 − 100)/100 = 2,0. Od aktywów obrotowych odejmuje się zapasy jako najmniej płynne. (Wskaźnik bieżący = 300/100 = 3,0.)"}], "stopy": [{"q": "Która ze stóp procentowych NBP wyznacza GÓRNĄ granicę korytarza wahań stóp rynkowych overnight i jest oprocentowaniem kredytu zaciąganego przez banki w NBP pod zastaw papierów wartościowych?", "options": ["Stopa lombardowa", "Stopa referencyjna", "Stopa depozytowa", "Stopa redyskontowa weksli"], "correct": 0, "explain": "Stopa lombardowa to koszt kredytu lombardowego (pod zastaw papierów) i stanowi górne ograniczenie korytarza; stopa depozytowa wyznacza dolne."}, {"q": "Korytarz stóp NBP jest zwykle symetryczny wokół stopy referencyjnej. Jeśli stopa referencyjna wynosi 5,75%, a korytarz jest symetryczny o szerokości ±1,00 pkt proc., to jakie są odpowiednio stopa lombardowa i depozytowa?", "options": ["Lombardowa 6,75% i depozytowa 4,75%", "Lombardowa 4,75% i depozytowa 6,75%", "Lombardowa 6,75% i depozytowa 5,75%", "Lombardowa 5,75% i depozytowa 4,75%"], "correct": 0, "explain": "Lombardowa = referencyjna + 1,00 = 6,75% (górna granica), depozytowa = referencyjna − 1,00 = 4,75% (dolna granica)."}, {"q": "Czym jest stopa rezerwy obowiązkowej i jaki jest jej podstawowy mechanizm oddziaływania na gospodarkę?", "options": ["Procent depozytów, który banki muszą utrzymywać na rachunku w NBP — jej podniesienie ogranicza zdolność banków do kreacji kredytu", "Stopa, po której NBP skupuje od banków bony pieniężne w operacjach otwartego rynku", "Oprocentowanie środków, jakie banki lokują na koniec dnia w NBP", "Minimalna marża, jaką bank musi doliczyć do stopy referencyjnej przy udzielaniu kredytu"], "correct": 0, "explain": "Rezerwa obowiązkowa to odsetek depozytów odprowadzany do NBP; jej wzrost zmniejsza środki na akcję kredytową, działając restrykcyjnie."}, {"q": "Inwestor uzyskał 1 000 zł odsetek z lokaty bankowej. Ile wyniesie zryczałtowany podatek od zysków kapitałowych (tzw. podatek Belki) i jaka kwota trafi do inwestora?", "options": ["Podatek 190 zł, do wypłaty 810 zł", "Podatek 170 zł, do wypłaty 830 zł", "Podatek 90 zł, do wypłaty 910 zł", "Podatek 320 zł, do wypłaty 680 zł"], "correct": 0, "explain": "Podatek Belki to 19% od zysku: 0,19 · 1 000 = 190 zł, więc inwestorowi pozostaje 810 zł."}, {"q": "Która z poniższych par stawka–podatek jest poprawna w polskim systemie podatkowym (stan modelowy)?", "options": ["Podstawowa stawka VAT 23%", "Podstawowa stawka CIT 9%", "Pierwszy próg PIT (skala) 19%", "Stawka podatku od zysków kapitałowych 32%"], "correct": 0, "explain": "Podstawowa stawka VAT wynosi 23%. Podstawowy CIT to 19% (9% to stawka preferencyjna dla małych podatników), pierwszy próg skali PIT to 12%, a podatek Belki to 19%."}, {"q": "Mały podatnik (przychody poniżej limitu) prowadzący spółkę z o.o. osiągnął dochód podatkowy 200 000 zł. Stosując preferencyjną stawkę CIT 9%, ile wyniesie należny podatek dochodowy?", "options": ["18 000 zł", "38 000 zł", "24 000 zł", "19 000 zł"], "correct": 0, "explain": "Preferencyjny CIT dla małego podatnika to 9%: 0,09 · 200 000 = 18 000 zł. Stawka 19% (38 000 zł) dotyczy podatników bez prawa do preferencji."}, {"q": "Bankowy Fundusz Gwarancyjny (BFG) gwarantuje depozyty klientów. Do jakiej kwoty (w przeliczeniu na złote) standardowo objęte są gwarancją środki jednego deponenta w jednym banku?", "options": ["Równowartość 100 000 EUR", "Równowartość 50 000 EUR", "Równowartość 100 000 zł", "Równowartość 250 000 EUR"], "correct": 0, "explain": "BFG gwarantuje środki deponenta do równowartości 100 000 EUR w jednym banku; powyżej tej kwoty środki nie są objęte gwarancją w standardowym trybie."}, {"q": "Rada Polityki Pieniężnej podnosi stopę referencyjną NBP. Jaki jest typowy, oczekiwany skutek tej decyzji (zależność przyczyna–skutek)?", "options": ["Wzrost oprocentowania kredytów i depozytów, schłodzenie popytu i presja na spadek inflacji", "Spadek oprocentowania kredytów i przyspieszenie akcji kredytowej", "Automatyczne obniżenie stawki VAT w celu wsparcia konsumpcji", "Natychmiastowe podniesienie kwoty gwarantowanej przez BFG"], "correct": 0, "explain": "Podwyżka stopy referencyjnej (polityka restrykcyjna) podnosi koszt pieniądza, ogranicza popyt i kredyt, co działa antyinflacyjnie. Stawki podatkowe i gwarancje BFG nie zależą od decyzji RPP."}], "k5": [{"q": "Która z poniższych metod oceny inwestycji NIE uwzględnia wartości pieniądza w czasie?", "options": ["Wartość bieżąca netto (NPV)", "Wewnętrzna stopa zwrotu (IRR)", "Prosty (księgowy) okres zwrotu", "Wskaźnik rentowności (PI)"], "correct": 2, "explain": "Prosty okres zwrotu sumuje nominalne przepływy aż do pokrycia nakładu i nie dyskontuje przyszłych kwot. NPV, IRR i PI bazują na przepływach zdyskontowanych."}, {"q": "Inwestycja ma NPV = 0. Co to oznacza dla wewnętrznej stopy zwrotu (IRR) i przyjętej stopy dyskontowej r?", "options": ["IRR jest równa stopie dyskontowej r", "IRR jest większa niż stopa dyskontowa r", "IRR jest mniejsza niż stopa dyskontowa r", "IRR nie istnieje, bo NPV = 0"], "correct": 0, "explain": "IRR to stopa, przy której NPV = 0. Skoro przy stopie r mamy NPV = 0, to właśnie r jest tą stopą, czyli IRR = r."}, {"q": "Wartość przyszła 1 000 zł po 2 latach przy rocznej stopie 10% i kapitalizacji rocznej wynosi:", "options": ["1 200 zł", "1 210 zł", "1 100 zł", "1 102 zł"], "correct": 1, "explain": "FV = 1000 · (1,10)² = 1000 · 1,21 = 1 210 zł. Odpowiedź 1 200 zł to błędne liczenie odsetek prostych (2 · 10%)."}, {"q": "Projekt wymaga nakładu 1 000 zł i daje wpływy: 600 zł w roku 1 oraz 600 zł w roku 2. Jaki jest prosty (nominalny) okres zwrotu?", "options": ["1 rok", "Około 1,67 roku", "2 lata", "Około 1,33 roku"], "correct": 1, "explain": "Po roku 1 odzyskano 600 zł, brakuje 400 zł. W roku 2 wpływa 600 zł, więc 400/600 ≈ 0,67 roku. Łącznie ≈ 1,67 roku."}, {"q": "Wskaźnik rentowności (PI) projektu wynosi 0,95. Jak należy zinterpretować ten projekt?", "options": ["Należy go przyjąć, bo PI jest dodatni", "Należy go odrzucić, bo NPV jest ujemne (PI mniejsze niż 1)", "Jest neutralny, bo PI jest bliski 1", "Należy go przyjąć, bo IRR jest większa niż 0"], "correct": 1, "explain": "PI = wartość bieżąca wpływów / nakład. PI mniejsze niż 1 oznacza, że PV wpływów nie pokrywa nakładu, czyli NPV jest ujemne — projekt odrzucamy."}, {"q": "Dlaczego przy wzajemnie wykluczających się projektach kryterium NPV bywa uznawane za bardziej wiarygodne niż IRR?", "options": ["IRR zawsze daje wynik w procentach, więc jest mniej dokładna", "NPV mierzy bezwzględny przyrost wartości i nie ma problemu wielokrotnych stóp zwrotu", "IRR nie uwzględnia wartości pieniądza w czasie", "NPV nie wymaga znajomości stopy dyskontowej"], "correct": 1, "explain": "NPV pokazuje realny przyrost wartości w zł i jest jednoznaczne, podczas gdy IRR może dawać wiele rozwiązań lub mylić przy różnej skali/profilu przepływów."}, {"q": "Współczynnik dyskontujący dla przepływu otrzymanego za 1 rok przy stopie 8% wynosi w przybliżeniu:", "options": ["1,08", "0,926", "0,920", "1,000"], "correct": 1, "explain": "Czynnik dyskontujący = 1 / (1 + r) = 1 / 1,08 ≈ 0,926. Wartość 1,08 to czynnik oprocentowania (kapitalizacji), a nie dyskontowania."}, {"q": "Która sytuacja jest typową PUŁAPKĄ metody IRR przy ocenie inwestycji?", "options": ["IRR nie da się policzyć dla projektów z dodatnim NPV", "Przy niekonwencjonalnych przepływach (zmiana znaku więcej niż raz) może istnieć wiele wartości IRR", "IRR zawsze prowadzi do tych samych decyzji co okres zwrotu", "IRR ignoruje wielkość nakładu początkowego"], "correct": 1, "explain": "Gdy znak przepływów zmienia się więcej niż raz (przepływy niekonwencjonalne), równanie NPV = 0 może mieć kilka pierwiastków, więc IRR bywa wieloznaczna lub niejednoznaczna."}], "k1": [{"q": "Zgodnie z zasadą memoriału przychody i koszty ujmuje się w księgach:", "options": ["W okresie, którego dotyczą, niezależnie od terminu zapłaty", "Wyłącznie w momencie wpływu lub wypływu środków pieniężnych", "Dopiero po zatwierdzeniu sprawozdania finansowego przez biegłego", "W okresie, w którym wystawiono fakturę, nawet jeśli dotyczy innego roku"], "correct": 0, "explain": "Zasada memoriału (art. 6 ust. 1 UoR) nakazuje ujmować wszystkie przychody i koszty dotyczące danego okresu, bez względu na to, kiedy nastąpi zapłata; ujęcie kasowe jest jej przeciwieństwem."}, {"q": "Która z poniższych sytuacji jest bezpośrednim zastosowaniem zasady współmierności przychodów i kosztów?", "options": ["Rozliczenie z góry zapłaconego czynszu przez czynne rozliczenia międzyokresowe kosztów", "Utworzenie odpisu aktualizującego na należność zagrożoną", "Wycena zapasów po cenie nabycia niższej od ceny sprzedaży", "Ujęcie środka trwałego w ewidencji w wartości początkowej"], "correct": 0, "explain": "Współmierność wymaga przypisania kosztów do przychodów tego samego okresu; czynne RMK przenoszą koszt zapłaconego z góry czynszu na okresy, których faktycznie dotyczy."}, {"q": "Zasada ostrożności (ostrożnej wyceny) w rachunkowości oznacza między innymi, że:", "options": ["Przewidywane straty i utratę wartości aktywów ujmuje się nawet, gdy są tylko prawdopodobne, a zyski dopiero gdy są zrealizowane", "Wszystkie aktywa wycenia się po wartości godziwej wyższej od ceny nabycia", "Przewidywane zyski ujmuje się od razu, a straty dopiero po ich poniesieniu", "Pomija się wszelkie ryzyka, których kwoty nie da się dokładnie ustalić"], "correct": 0, "explain": "Ostrożność (art. 7 UoR) jest asymetryczna: koszty, straty i spadki wartości ujmuje się przy ich uprawdopodobnieniu, a przychody i zyski dopiero po realizacji — by nie zawyżać wyniku."}, {"q": "Jednostka jest wezwana do zapłaty kary umownej; na dzień bilansowy wynik sporu jest niepewny, ale zapłata jest prawdopodobna, a kwotę da się oszacować. Zgodnie z zasadą ostrożności jednostka powinna:", "options": ["Utworzyć rezerwę na przewidywaną stratę i obciążyć nią wynik okresu", "Nie ujmować nic, ponieważ kara nie została jeszcze zapłacona", "Ująć karę jako przychód przyszłych okresów", "Zwiększyć wartość aktywów o spodziewane przyszłe korzyści"], "correct": 0, "explain": "Ostrożność nakazuje uwzględnić prawdopodobne, możliwe do oszacowania straty już w okresie ich uprawdopodobnienia — tworzy się na nie rezerwę obciążającą wynik."}, {"q": "Zasada kontynuacji działania (going concern) zakłada, że:", "options": ["Jednostka będzie kontynuować działalność w dającej się przewidzieć przyszłości w niezmienionym istotnie zakresie", "Składniki majątku zawsze wycenia się po cenach likwidacyjnych", "Sprawozdanie sporządza się przy założeniu zaprzestania działalności w ciągu roku", "Jednostka co roku zmienia profil działalności, aby maksymalizować zysk"], "correct": 0, "explain": "Założenie kontynuacji (art. 5 ust. 2 UoR) zakłada dalsze prowadzenie działalności w niezmienionym istotnie zakresie, co uzasadnia wycenę po cenach zwykłych, a nie likwidacyjnych."}, {"q": "Co jest najlepszym przykładem zastosowania zasady istotności w sprawozdawczości?", "options": ["Ujęcie zakupionego za 80 zł kalkulatora od razu w koszty zamiast amortyzować go przez lata", "Pominięcie w bilansie kredytu bankowego stanowiącego 40% sumy bilansowej", "Niewykazanie wszystkich istotnych zobowiązań, by poprawić obraz płynności", "Łączenie pozycji przychodów i kosztów w jedną kwotę netto bez uzasadnienia"], "correct": 0, "explain": "Istotność pozwala uprościć ujęcie pozycji nieznaczących dla oceny sytuacji jednostki — drobny składnik można odnieść wprost w koszty; nie wolno natomiast pomijać pozycji istotnych."}, {"q": "Jednostka sprzedała w grudniu towary za 50 000 zł, z czego klient zapłacił 30 000 zł w grudniu, a 20 000 zł dopiero w styczniu. Jaki przychód ze sprzedaży należy wykazać w grudniu zgodnie z zasadą memoriału?", "options": ["50 000 zł", "30 000 zł", "20 000 zł", "0 zł — przychód powstaje dopiero po pełnej zapłacie"], "correct": 0, "explain": "Memoriał nakazuje ująć cały przychód dotyczący okresu w momencie jego powstania (sprzedaży), niezależnie od terminu zapłaty — w grudniu wykazuje się pełne 50 000 zł."}, {"q": "Która funkcja rachunkowości polega na rejestrowaniu i przechowywaniu danych o operacjach gospodarczych, stanowiąc podstawę dowodową w razie sporów lub kontroli?", "options": ["Funkcja dowodowa (dokumentacyjna)", "Funkcja kontrolna", "Funkcja sprawozdawcza", "Funkcja analityczna"], "correct": 0, "explain": "Funkcja dowodowa polega na trwałym dokumentowaniu i przechowywaniu zapisów o operacjach, dzięki czemu księgi i dowody mogą służyć jako materiał dowodowy; kontrolna i analityczna pełnią inne role."}], "k2": [{"q": "Spółka kupiła grunt w 2008 r. za 200 000 zł. Na dzień bilansowy 2025 r. jego wartość rynkowa wynosi 750 000 zł. W myśl zasady kosztu historycznego (przy braku przeszacowania) w bilansie grunt zostanie wykazany w kwocie:", "options": ["750 000 zł, bo bilans pokazuje aktualną wartość rynkową aktywów", "200 000 zł, czyli w cenie nabycia", "475 000 zł, jako średnia ceny nabycia i wartości rynkowej", "550 000 zł, czyli wartość przyrostu wartości godziwej"], "correct": 1, "explain": "Koszt historyczny wycenia aktywo w cenie nabycia (200 000 zł); niezrealizowany wzrost wartości rynkowej nie jest ujmowany bez przeszacowania."}, {"q": "Która z poniższych cech NAJLEPIEJ opisuje przewagę wyceny w wartości godziwej nad kosztem historycznym?", "options": ["Jest zawsze tańsza i prostsza do ustalenia niż cena nabycia", "Lepiej odzwierciedla bieżącą wartość ekonomiczną składnika na dzień bilansowy", "Całkowicie eliminuje subiektywizm i szacunki z wyceny", "Gwarantuje, że wynik finansowy nigdy nie ulegnie wahaniom"], "correct": 1, "explain": "Zaletą wartości godziwej jest aktualność (odzwierciedla bieżące warunki rynkowe); jest jednak droższa, bardziej subiektywna i zwiększa zmienność wyniku."}, {"q": "W którym z elementów sprawozdania finansowego znajdziemy informację o stanie zobowiązań długoterminowych jednostki na dany moment?", "options": ["W rachunku zysków i strat", "W bilansie (sprawozdaniu z sytuacji finansowej)", "W rachunku przepływów pieniężnych", "W zestawieniu zmian w kapitale własnym"], "correct": 1, "explain": "Bilans prezentuje stan aktywów i pasywów (w tym zobowiązań) na dzień bilansowy; pozostałe sprawozdania pokazują strumienie lub zmiany za okres."}, {"q": "Jednostka stosuje metodę pośrednią w rachunku przepływów pieniężnych. Amortyzacja za okres wyniosła 40 000 zł. Jaką korektę wyniku finansowego netto należy wykonać w działalności operacyjnej?", "options": ["Odjąć 40 000 zł, bo amortyzacja to wydatek pieniężny", "Dodać 40 000 zł, bo to koszt niepieniężny obniżający wynik", "Nie korygować, bo amortyzacja nie wpływa na wynik finansowy", "Dodać 40 000 zł w działalności inwestycyjnej"], "correct": 1, "explain": "Amortyzacja obniża wynik, ale nie powoduje wypływu gotówki, więc w metodzie pośredniej dodaje się ją z powrotem do wyniku w działalności operacyjnej."}, {"q": "Aktywa obrotowe spółki wynoszą 300 000 zł, zobowiązania krótkoterminowe 120 000 zł, a kapitał własny 500 000 zł. Ile wynoszą aktywa trwałe, jeśli suma bilansowa równa się sumie kapitału własnego i wszystkich zobowiązań, a jedynymi zobowiązaniami są te krótkoterminowe?", "options": ["620 000 zł", "320 000 zł", "180 000 zł", "800 000 zł"], "correct": 1, "explain": "Suma pasywów = 500 000 + 120 000 = 620 000 zł = suma aktywów; aktywa trwałe = 620 000 − 300 000 (obrotowe) = 320 000 zł."}, {"q": "Która operacja zostanie wykazana w rachunku przepływów pieniężnych jako wpływ z działalności FINANSOWEJ?", "options": ["Sprzedaż wyrobów gotowych za gotówkę", "Zaciągnięcie kredytu bankowego", "Sprzedaż zbędnej maszyny produkcyjnej", "Zapłata podatku dochodowego"], "correct": 1, "explain": "Zaciągnięcie kredytu to pozyskanie kapitału obcego, czyli przepływ finansowy; sprzedaż wyrobów to działalność operacyjna, a sprzedaż maszyny inwestycyjna."}, {"q": "Zgodnie z zasadą ostrożności zapasy wycenia się w cenie nabycia lub niższej cenie sprzedaży netto. Zapas kosztował 50 000 zł, a jego możliwa do uzyskania cena sprzedaży netto spadła do 42 000 zł. W jakiej kwocie wykazać zapas w bilansie?", "options": ["50 000 zł, bo obowiązuje koszt historyczny", "42 000 zł, czyli w niższej cenie sprzedaży netto", "46 000 zł, jako wartość średnia", "8 000 zł, czyli kwotę odpisu aktualizującego"], "correct": 1, "explain": "Zasada ostrożności nakazuje wycenę zapasu w wartości niższej (42 000 zł), tworząc odpis aktualizujący 8 000 zł obciążający wynik."}, {"q": "Co odróżnia rachunek zysków i strat od bilansu pod względem ujęcia czasu?", "options": ["RZiS prezentuje stan na dzień, a bilans strumienie za okres", "RZiS prezentuje strumienie (przychody i koszty) za okres, a bilans stan na dzień bilansowy", "Oba prezentują wyłącznie stan na dzień bilansowy", "Oba prezentują wyłącznie strumienie za okres sprawozdawczy"], "correct": 1, "explain": "RZiS jest sprawozdaniem strumieniowym (przychody i koszty narastająco za okres), a bilans jest sprawozdaniem momentowym (stan aktywów i pasywów na dany dzień)."}], "k3": [{"q": "Wskaźnik bieżącej płynności (current ratio) liczony jest jako:", "options": ["Aktywa obrotowe ÷ zobowiązania krótkoterminowe", "(Aktywa obrotowe − zapasy) ÷ zobowiązania krótkoterminowe", "Środki pieniężne ÷ zobowiązania krótkoterminowe", "Aktywa obrotowe ÷ zobowiązania ogółem"], "correct": 0, "explain": "Current ratio = aktywa obrotowe ÷ zobowiązania krótkoterminowe. Wariant z odjęciem zapasów to wskaźnik szybki (quick ratio), a wersja z samymi środkami pieniężnymi to wskaźnik gotówkowy."}, {"q": "Spółka ma ROS = 5%, rotację aktywów = 2,0 oraz mnożnik kapitału własnego (aktywa/kapitał własny) = 1,5. Ile wynosi ROE według modelu DuPont?", "options": ["15%", "10%", "7,5%", "20%"], "correct": 0, "explain": "DuPont: ROE = ROS · rotacja aktywów · mnożnik kapitału = 0,05 · 2,0 · 1,5 = 0,15, czyli 15%. Pozostałe wyniki pomijają jeden z czynników mnożenia."}, {"q": "Która z poniższych relacji najlepiej opisuje, dlaczego ROE może być wyższe niż ROA?", "options": ["Bo spółka finansuje aktywa długiem, a dodatnia dźwignia finansowa zwiększa zwrot dla właścicieli", "Bo ROE zawsze liczone jest od zysku brutto, a ROA od zysku netto", "Bo ROE pomija koszty operacyjne, których ROA nie pomija", "Bo wyższa rotacja zapasów automatycznie podnosi ROE ponad ROA"], "correct": 0, "explain": "Gdy kapitał własny jest mniejszy od aktywów (część finansowana długiem), mnożnik kapitału jest większy niż 1, więc ROE = ROA · mnożnik kapitału przewyższa ROA — to efekt dodatniej dźwigni finansowej."}, {"q": "Wskaźnik ogólnego zadłużenia (debt ratio) wzrósł z 0,4 do 0,6 przy niezmienionych aktywach. Co to oznacza?", "options": ["Udział kapitału obcego w finansowaniu aktywów wzrósł, a udział kapitału własnego spadł", "Spółka zwiększyła płynność bieżącą", "Rentowność sprzedaży (ROS) musiała wzrosnąć", "Aktywa obrotowe wzrosły kosztem trwałych"], "correct": 0, "explain": "Debt ratio = zobowiązania ÷ aktywa. Wzrost z 0,4 do 0,6 oznacza, że dług finansuje już 60% aktywów, więc udział kapitału własnego spadł z 60% do 40%. Wskaźnik nie mówi nic o płynności ani rentowności."}, {"q": "Spółka A i spółka B mają identyczne ROA = 8%. Spółka A ma wskaźnik D/E = 0,5, a spółka B D/E = 1,5. Która spółka — przy dodatniej dźwigni — powinna mieć wyższe ROE i dlaczego?", "options": ["Spółka B, bo wyższe D/E oznacza wyższy mnożnik kapitału własnego", "Spółka A, bo niższe D/E zawsze daje wyższe ROE", "Obie tak samo, bo ROA jest identyczne", "Spółka A, bo mniejszy dług oznacza mniejsze koszty odsetkowe i wyższy zysk"], "correct": 0, "explain": "Mnożnik kapitału = 1 + D/E. Dla B wynosi 2,5, dla A tylko 1,5. Przy tym samym ROA i dodatniej dźwigni ROE = ROA · mnożnik jest wyższe dla B. Identyczne ROA oznacza, że efekt odsetek został już uwzględniony."}, {"q": "Który wskaźnik zalicza się do grupy wskaźników sprawności (aktywności) działania?", "options": ["Rotacja należności w dniach", "Wskaźnik bieżącej płynności", "Marża zysku netto (ROS)", "Wskaźnik pokrycia odsetek (TIE)"], "correct": 0, "explain": "Wskaźniki sprawności mierzą efektywność wykorzystania zasobów — rotacja należności (DSO) pokazuje, jak szybko spółka ściąga należności. Płynność to grupa płynnościowa, ROS to rentowność, a TIE to wskaźnik zdolności obsługi długu."}, {"q": "W modelu Altmana Z-score dla spółek produkcyjnych notowanych na giełdzie wartość Z poniżej 1,81 interpretuje się jako:", "options": ["Strefa zagrożenia — wysokie ryzyko bankructwa", "Strefa bezpieczna — niskie ryzyko bankructwa", "Strefa neutralna („szara strefa\")", "Wynik nieistotny statystycznie, model się nie stosuje"], "correct": 0, "explain": "W klasycznym modelu Altmana Z mniejsze niż 1,81 oznacza strefę zagrożenia (wysokie ryzyko upadłości), Z większe niż 2,99 to strefa bezpieczna, a przedział 1,81–2,99 to „szara strefa\"."}, {"q": "Który z poniższych elementów NIE jest składnikiem (zmienną) klasycznego modelu Altman Z-score?", "options": ["Wskaźnik bieżącej płynności (aktywa obrotowe ÷ zobowiązania krótkoterminowe)", "Kapitał obrotowy ÷ aktywa ogółem", "Zysk zatrzymany ÷ aktywa ogółem", "EBIT ÷ aktywa ogółem"], "correct": 0, "explain": "Pięć zmiennych modelu Altmana to: kapitał obrotowy/aktywa, zysk zatrzymany/aktywa, EBIT/aktywa, wartość rynkowa kapitału/zobowiązania oraz przychody/aktywa. Sam wskaźnik bieżącej płynności nie wchodzi bezpośrednio do wzoru — choć kapitał obrotowy go pośrednio odzwierciedla."}], "k4": [{"q": "W rachunku kosztów zmiennych (variable costing) do kosztu wytworzenia produktu zalicza się wyłącznie:", "options": ["wszystkie koszty produkcyjne, w tym stałe koszty pośrednie produkcji", "koszty zmienne produkcyjne; stałe koszty pośrednie produkcji traktuje się jako koszt okresu", "koszty zmienne produkcyjne oraz zmienne koszty sprzedaży i zarządu", "koszty stałe produkcji, a koszty zmienne odnosi się bezpośrednio na wynik okresu"], "correct": 1, "explain": "W rachunku kosztów zmiennych zapasy wycenia się tylko po kosztach zmiennych produkcji, a stałe koszty pośrednie produkcji obciążają wynik okresu w całości (są kosztem okresu)."}, {"q": "Przedsiębiorstwo wyprodukowało 10 000 szt., a sprzedało 8 000 szt. Stałe koszty pośrednie produkcji wyniosły 40 000 zł. O ile różni się wynik operacyjny w rachunku kosztów pełnych względem rachunku kosztów zmiennych?", "options": ["Wynik w kosztach pełnych jest wyższy o 8 000 zł", "Wynik w kosztach pełnych jest niższy o 8 000 zł", "Wyniki są równe, bo całość kosztów stałych obciąża okres", "Wynik w kosztach pełnych jest wyższy o 40 000 zł"], "correct": 0, "explain": "Produkcja przewyższa sprzedaż o 2 000 szt., więc 2 000 · (40 000/10 000) = 2 000 · 4 = 8 000 zł stałych kosztów zostaje 'zatrzymane' w zapasie. W kosztach pełnych wynik jest o tę kwotę wyższy."}, {"q": "Marża pokrycia (jednostkowa marża na pokrycie kosztów stałych) to:", "options": ["cena sprzedaży pomniejszona o jednostkowy całkowity koszt produktu", "cena sprzedaży pomniejszona o jednostkowy koszt zmienny", "przychód ze sprzedaży pomniejszony o koszty stałe", "zysk operacyjny przypadający na jednostkę produktu"], "correct": 1, "explain": "Marża pokrycia = cena − jednostkowy koszt zmienny; pokazuje, ile każda sprzedana sztuka 'dokłada' najpierw na pokrycie kosztów stałych, a po ich pokryciu na zysk."}, {"q": "Cena = 50 zł, jednostkowy koszt zmienny = 30 zł, koszty stałe = 120 000 zł. Próg rentowności wyrażony wartościowo (w przychodach) wynosi:", "options": ["240 000 zł", "300 000 zł", "6 000 zł", "360 000 zł"], "correct": 1, "explain": "Wskaźnik marży pokrycia = (50−30)/50 = 0,4. BEP wartościowy = koszty stałe / wskaźnik marży = 120 000 / 0,4 = 300 000 zł (co odpowiada 6 000 szt. · 50 zł)."}, {"q": "Która z poniższych zmian — przy pozostałych warunkach niezmienionych — OBNIŻY próg rentowności wyrażony w sztukach?", "options": ["Wzrost jednostkowego kosztu zmiennego", "Wzrost kosztów stałych", "Wzrost ceny sprzedaży jednostki", "Spadek jednostkowej marży pokrycia"], "correct": 2, "explain": "BEP (szt.) = koszty stałe / marża pokrycia. Wzrost ceny zwiększa marżę pokrycia (mianownik), więc próg w sztukach maleje. Pozostałe opcje albo podnoszą licznik, albo obniżają mianownik."}, {"q": "Firma chce osiągnąć zysk operacyjny 30 000 zł. Koszty stałe = 90 000 zł, marża pokrycia na sztukę = 15 zł. Ile sztuk trzeba sprzedać?", "options": ["6 000 szt.", "8 000 szt.", "2 000 szt.", "9 000 szt."], "correct": 1, "explain": "Ilość docelowa = (koszty stałe + zysk docelowy) / marża pokrycia = (90 000 + 30 000) / 15 = 120 000 / 15 = 8 000 szt."}, {"q": "Przy sprzedaży: przychody = 200 000 zł, koszty zmienne = 120 000 zł, koszty stałe = 50 000 zł. Stopień dźwigni operacyjnej (DOL) przy tym poziomie sprzedaży wynosi w przybliżeniu:", "options": ["1,67", "2,50", "2,67", "4,00"], "correct": 2, "explain": "Marża pokrycia = 200 000 − 120 000 = 80 000 zł; zysk operacyjny = 80 000 − 50 000 = 30 000 zł. DOL = marża pokrycia / zysk operacyjny = 80 000 / 30 000 ≈ 2,67."}, {"q": "Co oznacza stopień dźwigni operacyjnej (DOL) równy 3 przy danym poziomie sprzedaży?", "options": ["Wzrost sprzedaży o 1% zwiększy zysk operacyjny o około 3%", "Wzrost sprzedaży o 3% zwiększy zysk operacyjny o około 1%", "Zysk operacyjny jest trzykrotnie większy niż koszty stałe", "Próg rentowności jest osiągany przy 1/3 obecnej sprzedaży"], "correct": 0, "explain": "DOL to elastyczność zysku operacyjnego względem sprzedaży: DOL = procentowa zmiana EBIT / procentowa zmiana sprzedaży. DOL = 3 oznacza, że zmiana sprzedaży o 1% daje około 3% zmiany zysku operacyjnego."}], "k6": [{"q": "Zgodnie z modelem CAPM stopa zwrotu z akcji wynosi r = rf + β·(rm − rf). Dla rf = 4%, β = 1,2 oraz rm = 9% koszt kapitału własnego wynosi:", "options": ["10,0%", "16,0%", "10,8%", "6,0%"], "correct": 0, "explain": "r = 4% + 1,2·(9% − 4%) = 4% + 1,2·5% = 4% + 6% = 10%. Premia za ryzyko liczona jest od różnicy (rm − rf), nie od całego rm."}, {"q": "Spółka ma kapitał własny E = 600, dług D = 400, koszt kapitału własnego 12%, koszt długu przed opodatkowaniem 6%, stawkę podatku 19%. Ile wynosi WACC?", "options": ["9,144%", "9,60%", "9,72%", "8,856%"], "correct": 0, "explain": "WACC = (600/1000)·12% + (400/1000)·6%·(1 − 0,19) = 7,2% + 0,4·6%·0,81 = 7,2% + 1,944% = 9,144%. Tarczę podatkową stosuje się tylko do kosztu długu."}, {"q": "Która z poniższych wielkości w formule WACC powinna być skorygowana o tarczę podatkową (przemnożona przez (1 − T))?", "options": ["Koszt długu", "Koszt kapitału własnego", "Wartość rynkowa kapitału własnego", "Współczynnik β"], "correct": 0, "explain": "Odsetki od długu są kosztem uzyskania przychodu, więc tylko koszt długu mnożymy przez (1 − T). Dywidendy nie są kosztem podatkowym, dlatego kosztu kapitału własnego się nie koryguje."}, {"q": "Zgodnie z teorią Modiglianiego-Millera BEZ podatków (twierdzenie I) wartość przedsiębiorstwa:", "options": ["Jest niezależna od struktury kapitału", "Rośnie wraz ze wzrostem zadłużenia dzięki tarczy podatkowej", "Jest maksymalna przy 100% finansowaniu długiem", "Maleje wraz ze wzrostem udziału długu z powodu ryzyka bankructwa"], "correct": 0, "explain": "W świecie MM bez podatków wartość firmy zależy wyłącznie od jej aktywów i zdolności generowania zysku, a nie od sposobu finansowania — struktura kapitału jest nieistotna. Tarcza podatkowa pojawia się dopiero w wersji z podatkami."}, {"q": "Spółka ma dług o wartości 500 oprocentowany 8% rocznie, a stawka podatku dochodowego to 19%. Ile wynosi roczna wartość odsetkowej tarczy podatkowej?", "options": ["7,6", "40,0", "95,0", "32,4"], "correct": 0, "explain": "Tarcza = odsetki · stawka podatku = (500·8%)·19% = 40·0,19 = 7,6. Kwota 40 to same odsetki (oszczędność dotyczy tylko części odpowiadającej stawce podatku)."}, {"q": "Stopień dźwigni finansowej (DFL) dla spółki o EBIT = 200 i kosztach odsetkowych I = 50 wynosi:", "options": ["1,33", "0,75", "4,00", "2,50"], "correct": 0, "explain": "DFL = EBIT / (EBIT − I) = 200 / (200 − 50) = 200 / 150 ≈ 1,33. Mianownik to zysk brutto po odjęciu odsetek, a nie sam koszt odsetek."}, {"q": "Zgodnie z teorią substytucji (trade-off) optymalna struktura kapitału jest osiągana, gdy:", "options": ["Krańcowa korzyść z tarczy podatkowej zrównuje się z krańcowym kosztem trudności finansowych", "Udział długu wynosi dokładnie 50% wartości firmy", "Koszt kapitału własnego jest równy kosztowi długu", "Firma całkowicie eliminuje dług, minimalizując ryzyko bankructwa"], "correct": 0, "explain": "Teoria trade-off równoważy korzyści podatkowe z długu z rosnącymi kosztami trudności finansowych (bankructwa). Optimum to punkt, w którym krańcowe korzyści zrównują się z krańcowymi kosztami, a nie sztywny udział procentowy."}, {"q": "Spółka zwiększa udział długu w finansowaniu (przy pozostałych warunkach niezmienionych). Jaki jest typowy bezpośredni skutek dla stopnia dźwigni finansowej (DFL) i ryzyka właścicieli?", "options": ["DFL rośnie, a zmienność zysku na akcję (EPS) zwiększa się", "DFL maleje, ponieważ odsetki obniżają podatek", "DFL pozostaje stały, bo zależy tylko od kosztów stałych operacyjnych", "DFL rośnie, ale zmienność EPS maleje dzięki tarczy podatkowej"], "correct": 0, "explain": "Większe odsetki zwiększają DFL (EBIT/(EBIT − I) rośnie, gdy I rośnie), co wzmacnia wahania EPS przy danej zmianie EBIT — rośnie więc ryzyko finansowe właścicieli. DFL operacyjny mierzy inna miara (DOL)."}], "k7": [{"q": "Kapitał obrotowy netto (KON) w ujęciu majątkowym oblicza się jako:", "options": ["Aktywa obrotowe − zobowiązania bieżące", "Aktywa trwałe − kapitał własny", "Zobowiązania bieżące − zapasy", "Kapitał stały − aktywa obrotowe"], "correct": 0, "explain": "W ujęciu majątkowym KON = aktywa obrotowe − zobowiązania bieżące; to część aktywów obrotowych finansowana kapitałem stałym."}, {"q": "Cykl konwersji gotówki (CCC) wyraża się wzorem:", "options": ["DSO + DIO + DPO", "DSO + DIO − DPO", "DPO − DIO − DSO", "DIO − DSO + DPO"], "correct": 1, "explain": "CCC = okres rotacji zapasów (DIO) + okres ściągania należności (DSO) − okres regulowania zobowiązań (DPO); odejmujemy DPO, bo kredyt kupiecki finansuje cykl."}, {"q": "Przedsiębiorstwo: DIO = 60 dni, DSO = 45 dni, DPO = 30 dni. Cykl konwersji gotówki wynosi:", "options": ["135 dni", "75 dni", "45 dni", "15 dni"], "correct": 1, "explain": "CCC = 60 + 45 − 30 = 75 dni. Dystraktory to suma wszystkich (135) lub błędne odjęcia."}, {"q": "Która z poniższych zmian — przy pozostałych warunkach bez zmian — SKRACA cykl konwersji gotówki?", "options": ["Wydłużenie terminów płatności udzielanych odbiorcom", "Zwiększenie poziomu zapasów w magazynie", "Wynegocjowanie dłuższych terminów płatności u dostawców", "Wcześniejsze regulowanie zobowiązań wobec dostawców"], "correct": 2, "explain": "Dłuższy DPO (wzrost odjemnika) skraca CCC. Pozostałe opcje wydłużają DSO, DIO lub skracają DPO, czyli wydłużają cykl."}, {"q": "Agresywna (ofensywna) strategia zarządzania kapitałem obrotowym netto charakteryzuje się przede wszystkim:", "options": ["Wysokim poziomem KON i dużą rezerwą płynności", "Niskim (często bliskim zera lub ujemnym) KON i wysokim ryzykiem utraty płynności", "Finansowaniem aktywów obrotowych wyłącznie kapitałem własnym", "Maksymalizacją zapasów bezpieczeństwa kosztem rentowności"], "correct": 1, "explain": "Strategia agresywna minimalizuje KON (tani kapitał krótkoterminowy), podnosząc rentowność, ale zwiększając ryzyko utraty płynności."}, {"q": "W modelu EOQ (ekonomicznej wielkości zamówienia) optymalna wielkość zamówienia wynosi:", "options": ["Q* = √(2 · D · K_z / k_u)", "Q* = 2 · D · K_z · k_u", "Q* = √(D · k_u / 2 · K_z)", "Q* = (D · K_z) / 2"], "correct": 0, "explain": "EOQ minimalizuje sumę kosztów zamawiania i utrzymania: Q* = √(2 · D · K_z / k_u), gdzie D − popyt roczny, K_z − koszt jednego zamówienia, k_u − koszt utrzymania jednostki."}, {"q": "W punkcie optimum modelu EOQ zachodzi zależność, że roczne koszty zamawiania są:", "options": ["Większe niż roczne koszty utrzymania zapasów", "Mniejsze niż roczne koszty utrzymania zapasów", "Równe rocznym kosztom utrzymania zapasów", "Równe zeru"], "correct": 2, "explain": "EOQ leży w punkcie, w którym całkowity koszt jest minimalny — tam roczny koszt zamawiania (D/Q · K_z) zrównuje się z rocznym kosztem utrzymania (Q/2 · k_u)."}, {"q": "Ujemny kapitał obrotowy netto (zobowiązania bieżące większe niż aktywa obrotowe) NAJCZĘŚCIEJ oznacza, że:", "options": ["Przedsiębiorstwo finansuje część majątku trwałego zobowiązaniami bieżącymi", "Firma ma nadpłynność i nadmiar gotówki", "Aktywa trwałe są w całości pokryte kapitałem własnym", "Zapasy są finansowane wyłącznie kredytem długoterminowym"], "correct": 0, "explain": "Ujemny KON oznacza, że kapitał krótkoterminowy finansuje także aktywa trwałe — sygnał ryzyka płynności, a nie nadpłynności."}], "k8": [{"q": "W metodzie DCF opartej na FCFF (przepływy dla wszystkich dawców kapitału) właściwą stopą dyskontową jest:", "options": ["WACC (średni ważony koszt kapitału)", "koszt kapitału własnego (rₑ)", "koszt długu po opodatkowaniu (r_d·(1−t))", "stopa wolna od ryzyka (r_f)"], "correct": 0, "explain": "FCFF to przepływy należne wszystkim dawcom kapitału (właścicielom i wierzycielom), więc dyskontuje się je WACC; kosztem kapitału własnego dyskontuje się dopiero FCFE."}, {"q": "Firma ma kapitał własny o wartości rynkowej 600 i dług 400. Koszt kapitału własnego wynosi 12%, koszt długu 8%, a stopa podatku 19%. Ile wynosi WACC?", "options": ["9,79%", "10,40%", "8,96%", "11,20%"], "correct": 0, "explain": "WACC = (600/1000)·12% + (400/1000)·8%·(1−0,19) = 7,2% + 2,592% ≈ 9,79%; tarcza podatkowa obniża efektywny koszt długu do 6,48%."}, {"q": "Według modelu CAPM koszt kapitału własnego dla spółki o współczynniku β = 1,2, przy stopie wolnej od ryzyka 4% i premii za ryzyko rynkowe 5%, wynosi:", "options": ["10,0%", "6,0%", "9,0%", "11,0%"], "correct": 0, "explain": "rₑ = r_f + β·(r_m − r_f) = 4% + 1,2·5% = 4% + 6% = 10%; częstym błędem jest mnożenie β przez sumę (r_f + premia) zamiast samej premii."}, {"q": "Która z poniższych relacji poprawnie przekształca FCFF w FCFE (przy danym poziomie zadłużenia)?", "options": ["FCFE = FCFF − odsetki·(1 − t) + zaciągnięcie netto długu", "FCFE = FCFF + odsetki·(1 − t) − zaciągnięcie netto długu", "FCFE = FCFF − odsetki·(1 + t) + spłata długu", "FCFE = FCFF + amortyzacja − odsetki"], "correct": 0, "explain": "Od przepływu dla wszystkich dawców kapitału odejmuje się koszt odsetek po opodatkowaniu i dodaje saldo netto zaciągniętego/spłaconego długu, by zostać z przepływem dla właścicieli (FCFE)."}, {"q": "Spółka osiągnęła NOPAT = 120, zaangażowany kapitał operacyjny wynosi 800, a WACC = 10%. Ile wynosi EVA (ekonomiczna wartość dodana) i jak ją zinterpretować?", "options": ["EVA = 40 — spółka tworzy wartość, bo zwrot przewyższa koszt kapitału", "EVA = 40 — spółka niszczy wartość, bo NOPAT jest niższy od kapitału", "EVA = 80 — spółka tworzy wartość ponad koszt długu", "EVA = −40 — spółka nie pokrywa kosztu kapitału"], "correct": 0, "explain": "EVA = NOPAT − WACC·kapitał = 120 − 0,10·800 = 40; wartość dodatnia oznacza, że zysk operacyjny po opodatkowaniu przewyższa koszt całego zaangażowanego kapitału, więc spółka tworzy wartość."}, {"q": "W wycenie porównawczej znamy EBITDA spółki = 50 oraz mnożnik EV/EBITDA grupy porównawczej = 8. Dług netto wynosi 120. Jaka jest implikowana wartość kapitału własnego (equity value)?", "options": ["280", "400", "520", "320"], "correct": 0, "explain": "EV = 8·50 = 400 (wartość przedsiębiorstwa); wartość kapitału własnego = EV − dług netto = 400 − 120 = 280; pominięcie odjęcia długu netto daje błędne 400."}, {"q": "Dlaczego mnożnik EV/EBITDA jest często uznawany za bardziej porównywalny między spółkami niż wskaźnik P/E?", "options": ["Bo jest niezależny od struktury finansowania i polityki amortyzacji, podczas gdy P/E zależy od dźwigni i podatków", "Bo zawsze daje wyższą wycenę niż P/E, co premiuje spółki wzrostowe", "Bo opiera się na zysku netto, który jest mniej podatny na manipulacje niż EBITDA", "Bo EV dotyczy wyłącznie kapitału własnego, więc eliminuje wpływ wierzycieli"], "correct": 0, "explain": "EV/EBITDA porównuje wartość całego przedsiębiorstwa z zyskiem przed odsetkami, podatkiem i amortyzacją, więc neutralizuje różnice w zadłużeniu, stawce podatkowej i polityce amortyzacji; P/E (cena/zysk netto) jest wrażliwy na dźwignię i podatki."}, {"q": "Która z poniższych metod majątkowych wycenia przedsiębiorstwo przy założeniu zaprzestania działalności i sprzedaży aktywów po cenach możliwych do uzyskania w wymuszonej sprzedaży?", "options": ["Metoda likwidacyjna (wartość likwidacyjna)", "Metoda skorygowanych aktywów netto (przy kontynuacji działania)", "Metoda odtworzeniowa", "Metoda zdyskontowanych przepływów (DCF)"], "correct": 0, "explain": "Metoda likwidacyjna zakłada zaprzestanie działalności i wycenę aktywów po wartościach możliwych do uzyskania w sprzedaży (pomniejszonych o koszty likwidacji i zobowiązania); metoda skorygowanych aktywów netto i odtworzeniowa zakładają kontynuację, a DCF jest metodą dochodową, nie majątkową."}], "k9": [{"q": "Na którym segmencie rynku finansowego dokonuje się obrotu instrumentami o pierwotnym terminie zapadalności do 1 roku?", "options": ["Rynek pieniężny", "Rynek kapitałowy", "Rynek walutowy", "Rynek terminowy"], "correct": 0, "explain": "Rynek pieniężny z definicji obejmuje instrumenty krótkoterminowe (do 1 roku), np. bony skarbowe, certyfikaty depozytowe, lokaty międzybankowe; powyżej roku to już rynek kapitałowy."}, {"q": "Która z poniższych cech NAJLEPIEJ odróżnia rynek kapitałowy od rynku pieniężnego?", "options": ["Dłuższy horyzont inwestycji i finansowanie rozwoju, przy wyższym ryzyku", "Wyłączny obrót walutami obcymi", "Brak obrotu papierami udziałowymi", "Rozliczenia wyłącznie w trybie natychmiastowym (kasowym)"], "correct": 0, "explain": "Rynek kapitałowy obejmuje instrumenty o zapadalności powyżej 1 roku (akcje, obligacje), służy finansowaniu rozwoju i wiąże się z wyższym ryzykiem niż krótkoterminowy rynek pieniężny."}, {"q": "Inwestor kupuje akcję za 50 zł, po roku sprzedaje ją za 53 zł i w trakcie roku otrzymuje dywidendę 2 zł. Jaka jest jego całkowita stopa zwrotu?", "options": ["10%", "6%", "4%", "5%"], "correct": 0, "explain": "Stopa zwrotu = (zysk kapitałowy + dywidenda) / cena zakupu = (3 + 2) / 50 = 5/50 = 10%. Pominięcie dywidendy daje błędne 6%, a pominięcie zysku kapitałowego błędne 4%."}, {"q": "Która funkcja rynku finansowego polega na umożliwieniu szybkiej zamiany instrumentu na gotówkę bez znaczącej utraty wartości?", "options": ["Funkcja płynności (zapewnienia płynności)", "Funkcja alokacyjna", "Funkcja informacyjna (cenotwórcza)", "Funkcja transformacji terminów"], "correct": 0, "explain": "Funkcja płynności (zbywalności) oznacza możliwość szybkiego upłynnienia instrumentu po cenie zbliżonej do rynkowej; alokacyjna dotyczy kierowania kapitału do najefektywniejszych zastosowań, a informacyjna - odzwierciedlania informacji w cenach."}, {"q": "Zgodnie ze średnią (półsilną) formą hipotezy efektywności rynku (EMH), ceny odzwierciedlają:", "options": ["Wszystkie publicznie dostępne informacje", "Wyłącznie informacje zawarte w historycznych cenach", "Wszystkie informacje, łącznie z poufnymi (niepublicznymi)", "Jedynie prognozy analityków giełdowych"], "correct": 0, "explain": "Forma półsilna zakłada, że ceny zawierają wszystkie informacje publiczne (sprawozdania, komunikaty). Forma słaba ogranicza się do danych historycznych cen, a forma silna obejmuje także informacje poufne."}, {"q": "Jeśli rynek jest efektywny w formie słabej, to NIESKUTECZNA powinna być strategia oparta na:", "options": ["Analizie technicznej (wykresach historycznych cen)", "Analizie fundamentalnej sprawozdań finansowych", "Posiadaniu informacji poufnych zarządu", "Dywersyfikacji portfela"], "correct": 0, "explain": "Forma słaba mówi, że historyczne ceny są już w pełni odzwierciedlone w cenie bieżącej, więc analiza techniczna nie daje przewagi. Analiza fundamentalna i informacje poufne mogłyby działać dopóki rynek nie jest, odpowiednio, półsilny i silny."}, {"q": "Który z poniższych instrumentów jest instrumentem pochodnym (derywatem) rynku terminowego?", "options": ["Kontrakt futures na indeks giełdowy", "Obligacja skarbowa o stałym oprocentowaniu", "Akcja zwykła spółki notowanej na giełdzie", "Bon skarbowy"], "correct": 0, "explain": "Kontrakt futures jest instrumentem pochodnym - jego wartość zależy od instrumentu bazowego (tu indeksu). Obligacja i akcja to instrumenty bazowe (dłużny i udziałowy), a bon skarbowy to instrument rynku pieniężnego."}, {"q": "Na rynku walutowym podano kurs EUR/PLN = 4,30. Co to oznacza?", "options": ["Za 1 euro trzeba zapłacić 4,30 złotego", "Za 1 złotego trzeba zapłacić 4,30 euro", "Kurs złotego wzrósł o 4,30%", "Euro i złoty mają parytet 4,30 do 1 wyłącznie w transakcjach terminowych"], "correct": 0, "explain": "W notowaniu EUR/PLN walutą bazową jest euro, a kwotowaną złoty - kurs mówi, ile jednostek waluty kwotowanej (PLN) kosztuje jedna jednostka waluty bazowej (EUR), czyli 4,30 zł za 1 euro."}], "k10": [{"q": "Który organ NBP jest wyłącznie odpowiedzialny za ustalanie wysokości podstawowych stóp procentowych?", "options": ["Zarząd NBP", "Rada Polityki Pieniężnej", "Komisja Nadzoru Finansowego", "Prezes NBP jednoosobowo"], "correct": 1, "explain": "Stopy procentowe NBP ustala kolegialnie Rada Polityki Pieniężnej (RPP); Zarząd realizuje politykę, KNF nadzoruje rynek, a Prezes nie decyduje o stopach jednoosobowo."}, {"q": "Bank centralny chce ZWIĘKSZYĆ podaż pieniądza w gospodarce. Które z poniższych działań jest z tym spójne?", "options": ["Podniesienie stopy rezerwy obowiązkowej", "Skup papierów wartościowych w ramach operacji otwartego rynku", "Podniesienie stopy lombardowej", "Sprzedaż bonów pieniężnych bankom komercyjnym"], "correct": 1, "explain": "Skup papierów wartościowych zasila banki w płynność i zwiększa podaż pieniądza (ekspansja); pozostałe działania ją ograniczają (restrykcja)."}, {"q": "Co stanowi tzw. dolne ograniczenie korytarza stóp procentowych NBP, wyznaczając oprocentowanie środków deponowanych przez banki w NBP na koniec dnia?", "options": ["Stopa lombardowa", "Stopa redyskontowa weksli", "Stopa depozytowa", "Stopa referencyjna"], "correct": 2, "explain": "Stopa depozytowa to dolne ograniczenie korytarza (oprocentowanie depozytu O/N w NBP); stopa lombardowa wyznacza górne ograniczenie, a referencyjna leży w środku korytarza."}, {"q": "Bank ma depozyty objęte rezerwą obowiązkową w wysokości 40 mld zł, a stopa rezerwy obowiązkowej wynosi 3,5%. Ile wynosi kwota wymaganej rezerwy obowiązkowej?", "options": ["1,4 mld zł", "3,5 mld zł", "14 mld zł", "0,35 mld zł"], "correct": 0, "explain": "Rezerwa obowiązkowa = 40 mld zł · 3,5% = 40 · 0,035 = 1,4 mld zł."}, {"q": "Która sytuacja w finansach publicznych oznacza wystąpienie deficytu budżetowego?", "options": ["Dochody budżetu są większe niż jego wydatki", "Wydatki budżetu są większe niż jego dochody", "Dochody są równe wydatkom budżetu", "Dług publiczny jest większy niż roczne PKB"], "correct": 1, "explain": "Deficyt budżetowy występuje, gdy wydatki budżetu są większe niż jego dochody w danym okresie; nadwyżka to sytuacja odwrotna, a relacja długu do PKB to inna kategoria."}, {"q": "Które z poniższych jest instrumentem polityki FISKALNEJ, a nie monetarnej?", "options": ["Zmiana stopy rezerwy obowiązkowej", "Operacje otwartego rynku", "Zmiana stawek podatku dochodowego", "Ustalenie stopy lombardowej"], "correct": 2, "explain": "Polityka fiskalna posługuje się podatkami i wydatkami publicznymi (tu: stawki podatku); rezerwa obowiązkowa, operacje otwartego rynku i stopa lombardowa to instrumenty polityki monetarnej."}, {"q": "NBP realizuje strategię bezpośredniego celu inflacyjnego. Ile wynosi obecny cel inflacyjny NBP?", "options": ["2,5% z przedziałem odchyleń ±1 pkt proc.", "Dokładnie 2,0% bez przedziału odchyleń", "4,0% z przedziałem ±0,5 pkt proc.", "0% (pełna stabilność cen, brak inflacji)"], "correct": 0, "explain": "Cel inflacyjny NBP to 2,5% z dopuszczalnym pasmem odchyleń ±1 punkt procentowy (mierzony rocznym wskaźnikiem CPI)."}, {"q": "Zgodnie z którą zasadą bank centralny pełni funkcję ostatecznego źródła płynności dla banków komercyjnych zagrożonych przejściowymi kłopotami z płynnością?", "options": ["Pożyczkodawca ostatniej instancji (lender of last resort)", "Gwarant depozytów detalicznych", "Animator rynku akcji", "Doradca inwestycyjny banków"], "correct": 0, "explain": "Funkcja pożyczkodawcy ostatniej instancji oznacza dostarczanie płynności wypłacalnym bankom w sytuacji kryzysowej; gwarancją depozytów zajmuje się BFG, a nie NBP."}], "k11": [{"q": "Która z poniższych definicji NAJLEPIEJ opisuje deficyt budżetu państwa?", "options": ["Nadwyżka wydatków publicznych nad dochodami publicznymi w danym roku budżetowym", "Całkowita kwota niespłaconych zobowiązań Skarbu Państwa na koniec roku", "Różnica między eksportem a importem dóbr i usług", "Ujemne saldo rachunku obrotów bieżących bilansu płatniczego"], "correct": 0, "explain": "Deficyt budżetowy to przepływ roczny: nadwyżka wydatków nad dochodami w danym roku. Skumulowane deficyty tworzą dług publiczny (odpowiedź B myli zasób z przepływem)."}, {"q": "Podatki dzielimy na bezpośrednie i pośrednie. Która grupa zawiera WYŁĄCZNIE podatki pośrednie?", "options": ["VAT, akcyza, podatek od gier", "PIT, CIT, podatek od nieruchomości", "VAT, PIT, akcyza", "CIT, akcyza, podatek od spadków i darowizn"], "correct": 0, "explain": "Podatki pośrednie obciążają obrót/konsumpcję i są wliczone w cenę: VAT, akcyza, podatek od gier. PIT i CIT to podatki bezpośrednie (obciążają dochód podatnika)."}, {"q": "Przedsiębiorca (czynny podatnik VAT) kupił towar za 1 000 zł netto, a sprzedał go za 1 500 zł netto. Stawka VAT wynosi 23%. Ile wyniesie VAT do zapłaty do urzędu skarbowego (VAT należny minus naliczony)?", "options": ["115 zł", "345 zł", "230 zł", "500 zł"], "correct": 0, "explain": "VAT należny = 1 500 · 23% = 345 zł; VAT naliczony = 1 000 · 23% = 230 zł. Do zapłaty: 345 − 230 = 115 zł (czyli 23% od marży 500 zł)."}, {"q": "Zgodnie z Konstytucją RP istnieje konstytucyjny próg ostrożnościowy zadłużenia. Państwowy dług publiczny nie może przekroczyć:", "options": ["3/5 (60%) wartości rocznego PKB", "1/2 (50%) wartości rocznego PKB", "3% wartości rocznego PKB", "9/10 (90%) wartości rocznego PKB"], "correct": 0, "explain": "Art. 216 ust. 5 Konstytucji RP zakazuje zaciągania zobowiązań powodujących przekroczenie 3/5 (60%) PKB przez dług publiczny. Próg 3% PKB dotyczy deficytu (kryterium z Maastricht), nie długu."}, {"q": "Która cecha odróżnia podatek od opłaty publicznej?", "options": ["Podatek jest świadczeniem nieodpłatnym, a opłata wiąże się z konkretnym świadczeniem ze strony organu", "Podatek jest dobrowolny, a opłata przymusowa", "Podatek jest zwrotny, a opłata bezzwrotna", "Podatek pobiera samorząd, a opłatę wyłącznie budżet państwa"], "correct": 0, "explain": "Podatek jest nieodpłatny (brak konkretnego świadczenia wzajemnego), opłata zaś wiąże się z określoną czynnością/usługą organu. Oba są jednak przymusowe i bezzwrotne, co eliminuje pozostałe odpowiedzi."}, {"q": "Ceteris paribus, który czynnik bezpośrednio ZWIĘKSZA deficyt budżetu państwa w danym roku?", "options": ["Wzrost wydatków na świadczenia społeczne przy niezmienionych dochodach podatkowych", "Wzrost wpływów z podatku VAT przy niezmienionych wydatkach", "Spłata części dotychczasowego długu publicznego z nadwyżki", "Wzrost dochodów z prywatyzacji majątku Skarbu Państwa"], "correct": 0, "explain": "Deficyt rośnie, gdy wydatki rosną szybciej niż dochody. Wzrost wpływów VAT (B) zmniejsza deficyt; spłata długu (C) nie jest pozycją zwiększającą deficyt, a wpływy z prywatyzacji (D) są przychodem zmniejszającym potrzeby pożyczkowe."}, {"q": "Która z poniższych zasad budżetowych oznacza, że wszystkie dochody i wydatki ujmuje się w budżecie w pełnych kwotach, bez ich wzajemnego kompensowania (saldowania)?", "options": ["Zasada zupełności (budżetowania brutto)", "Zasada jedności materialnej", "Zasada równowagi budżetowej", "Zasada uprzedniości"], "correct": 0, "explain": "Zasada zupełności (powszechności, budżetowania brutto) wymaga wykazywania dochodów i wydatków w pełnych kwotach. Jedność materialna mówi, że dochody nie są przypisane do konkretnych wydatków, a równowaga dotyczy relacji dochodów do wydatków."}, {"q": "Podatnik PIT na skali rozlicza się od dochodu 90 000 zł. Pierwszy próg do 120 000 zł jest opodatkowany stawką 12%, a kwota wolna od podatku wynosi 30 000 zł (kwota zmniejszająca podatek 3 600 zł). Ile wyniesie podatek należny (przed odliczeniami od podatku)?", "options": ["7 200 zł", "10 800 zł", "8 400 zł", "6 480 zł"], "correct": 0, "explain": "Podatek = 90 000 · 12% − 3 600 = 10 800 − 3 600 = 7 200 zł. Równoważnie: opodatkowana jest nadwyżka ponad kwotę wolną, czyli (90 000 − 30 000) · 12% = 7 200 zł. Odpowiedź B pomija kwotę zmniejszającą podatek."}], "k12": [{"q": "Polska firma transportowa eksploatuje flotę ciężarówek wyłącznie na terenie Niemiec. Wypracowany tam zysk i wynagrodzenia kierowców (polskich rezydentów) zostaną zaliczone do:", "options": ["PKB Polski, bo produkcja należy do polskich podmiotów", "PNB Polski, bo dochód uzyskali polscy rezydenci za granicą", "PKB Niemiec i PNB Niemiec jednocześnie", "wyłącznie PKB Niemiec, a nie do PNB żadnego kraju"], "correct": 1, "explain": "PNB liczy dochody rezydentów danego kraju niezależnie od miejsca ich osiągnięcia — dochód polskich rezydentów za granicą wchodzi do PNB Polski (oraz do PKB Niemiec wg miejsca wytworzenia)."}, {"q": "Która zależność poprawnie wiąże PKB i PNB danego kraju?", "options": ["PNB = PKB + dochody netto rezydentów z zagranicy", "PNB = PKB − amortyzacja", "PNB = PKB + saldo eksportu i importu", "PNB = PKB + podatki pośrednie − subwencje"], "correct": 0, "explain": "PNB = PKB powiększone o dochody pierwotne netto rezydentów z zagranicy (dochody rezydentów za granicą minus dochody nierezydentów w kraju); pozostałe wzory opisują inne agregaty."}, {"q": "W gospodarce ceny rosną, ale wolniej niż w poprzednim kwartale (np. inflacja spadła z 8% do 5%). To zjawisko nazywamy:", "options": ["deflacją", "dezinflacją", "stagflacją", "reflacją"], "correct": 1, "explain": "Dezinflacja to spadek tempa inflacji przy wciąż dodatnim wzroście cen; deflacja oznaczałaby spadek poziomu cen (inflacja mniejsza niż 0)."}, {"q": "Bezrobotny, który stracił pracę w stoczni, bo popyt na statki trwale spadł i jego kwalifikacje przestały być potrzebne, to przykład bezrobocia:", "options": ["frykcyjnego", "sezonowego", "strukturalnego", "cyklicznego"], "correct": 2, "explain": "Trwałe niedopasowanie kwalifikacji do struktury popytu na pracę to bezrobocie strukturalne; frykcyjne dotyczy krótkiego okresu zmiany pracy, a cykliczne wynika z recesji."}, {"q": "Stopa bezrobocia naturalnego obejmuje:", "options": ["wyłącznie bezrobocie cykliczne", "bezrobocie frykcyjne i strukturalne", "całkowite bezrobocie w szczycie recesji", "tylko osoby bierne zawodowo"], "correct": 1, "explain": "Bezrobocie naturalne to suma frykcyjnego i strukturalnego — występuje nawet przy pełnym wykorzystaniu mocy wytwórczych; bezrobocie cykliczne jest z definicji poza stopą naturalną."}, {"q": "Punkt cyklu koniunkturalnego, w którym PKB osiąga najniższy poziom i kończy się faza spadku, a zaczyna ożywienie, to:", "options": ["szczyt (peak)", "ekspansja", "dno (trough)", "recesja"], "correct": 2, "explain": "Dno (trough) to dolny punkt zwrotny cyklu — moment przejścia od recesji/kontrakcji do ożywienia; szczyt jest górnym punktem zwrotnym."}, {"q": "Nominalna stopa procentowa lokaty wynosi 9%, a inflacja 4%. Korzystając z dokładnego równania Fishera (1 + i) = (1 + r) · (1 + π), realna stopa procentowa wynosi w przybliżeniu:", "options": ["5,00%", "4,81%", "13,00%", "2,25%"], "correct": 1, "explain": "r = (1,09 / 1,04) − 1 ≈ 0,0481, czyli ≈ 4,81%. Przybliżenie r ≈ i − π daje 5% — to wynik uproszczony, nie dokładny."}, {"q": "Inflacja okazała się wyższa od oczekiwanej. Kto na tym typowo zyskuje?", "options": ["wierzyciele udzielający pożyczek o stałym oprocentowaniu", "dłużnicy spłacający dług o stałym oprocentowaniu", "posiadacze gotówki trzymanej w domu", "osoby o dochodach nominalnie sztywnych (np. stała emerytura)"], "correct": 1, "explain": "Nieoczekiwana inflacja obniża realną wartość spłacanego długu o stałej stopie, więc dłużnik oddaje pieniądz o mniejszej sile nabywczej — traci wierzyciel oraz posiadacze gotówki i sztywnych dochodów."}], "t1": [{"q": "Co dokładnie oznacza twierdzenie: „1-dniowy VaR portfela na poziomie ufności 99% wynosi 2 mln zł\"?", "options": ["Z prawdopodobieństwem 99% strata w ciągu jednego dnia nie przekroczy 2 mln zł", "Średnia oczekiwana strata portfela w ciągu jednego dnia wynosi 2 mln zł", "Maksymalna możliwa strata portfela w ciągu jednego dnia to 2 mln zł", "Z prawdopodobieństwem 99% portfel zyska co najmniej 2 mln zł dziennie"], "correct": 0, "explain": "VaR to kwantyl rozkładu strat: na poziomie ufności 99% strata nie przekroczy VaR z prawdopodobieństwem 99% (w ok. 1% dni może być większa). VaR nie jest ani wartością oczekiwaną, ani stratą maksymalną."}, {"q": "Bank szacuje 1-dniowy VaR metodą parametryczną dla pozycji o wartości 10 mln zł. Dzienne odchylenie standardowe stopy zwrotu σ = 2%, a kwantyl rozkładu normalnego dla 99% to z = 2,33. Przy założeniu zerowej średniej VaR wynosi w przybliżeniu:", "options": ["466 tys. zł", "200 tys. zł", "2 330 tys. zł", "4 660 tys. zł"], "correct": 0, "explain": "VaR = z·σ·wartość pozycji = 2,33·0,02·10 000 000 = 466 000 zł. Pominięcie z (200 tys.) lub mnożenie z przez całą wartość pozycji bez σ to typowe błędy rachunkowe."}, {"q": "Która z poniższych wielkości jest poprawnym mnożnikiem (kwantylem z) rozkładu normalnego standardowego dla jednostronnego poziomu ufności 95% w metodzie parametrycznej VaR?", "options": ["1,65", "1,96", "2,33", "2,58"], "correct": 0, "explain": "Dla 95% jednostronnie z ≈ 1,65. Wartość 1,96 dotyczy 95% dwustronnie, 2,33 to kwantyl dla 99% jednostronnie, a 2,58 dla 99% dwustronnie."}, {"q": "Bank wyznaczył 1-dniowy VaR równy 1 mln zł. Zakładając niezależne i jednakowo rozłożone dzienne stopy zwrotu (i.i.d.) oraz zerową średnią, jaki jest 10-dniowy VaR po przeskalowaniu „pierwiastkiem czasu\"?", "options": ["Około 3,16 mln zł", "10 mln zł", "1 mln zł", "100 mln zł"], "correct": 0, "explain": "Reguła √t: VaR(10 dni) = VaR(1 dzień)·√10 = 1 mln·3,162 ≈ 3,16 mln zł. Skalowanie liniowe (×10) lub kwadratowe (×100) jest błędne — skaluje się odchylenie standardowe przez √t."}, {"q": "Które stwierdzenie najlepiej opisuje różnicę między VaR a Expected Shortfall (ES) na tym samym poziomie ufności?", "options": ["ES to średnia strata pod warunkiem, że strata przekroczyła VaR, więc uwzględnia rozmiar strat w ogonie", "ES jest zawsze mniejszy niż VaR, bo pomija najgorsze scenariusze", "ES i VaR są zawsze sobie równe niezależnie od kształtu rozkładu", "ES to maksymalna możliwa strata, a VaR to strata oczekiwana"], "correct": 0, "explain": "ES (CVaR) uśrednia straty w ogonie poza progiem VaR, więc mierzy ich dotkliwość; jest ≥ VaR. VaR ignoruje rozkład strat przekraczających próg, co jest jego główną wadą."}, {"q": "Dlaczego Komitet Bazylejski (FRTB) zastąpił VaR przez Expected Shortfall jako podstawową miarę ryzyka rynkowego?", "options": ["VaR nie informuje o skali strat w ogonie i nie jest miarą subaddytywną (koherentną), a ES tę informację dostarcza", "ES jest łatwiejszy obliczeniowo i nie wymaga żadnych danych historycznych", "VaR systematycznie zawyża wymóg kapitałowy, a ES go obniża dla każdego portfela", "ES eliminuje potrzebę przeprowadzania testów wstecznych (backtestingu)"], "correct": 0, "explain": "VaR nie mówi, jak duże są straty przekraczające próg, i może naruszać subaddytywność (nie jest miarą koherentną). ES uwzględnia ogon rozkładu i jest subaddytywny, dlatego FRTB go przyjął."}, {"q": "Która cecha jest podstawowym ograniczeniem metody parametrycznej (wariancja-kowariancja) VaR?", "options": ["Zakłada normalność rozkładu stóp zwrotu, więc niedoszacowuje ryzyka przy „grubych ogonach\" i pozycjach nieliniowych (opcjach)", "Wymaga symulacji Monte Carlo dla każdej pozycji w portfelu", "Nie da się jej zastosować, gdy znane są macierz kowariancji i odchylenia standardowe", "Daje wyniki wyłącznie dla pojedynczego instrumentu, nigdy dla portfela"], "correct": 0, "explain": "Metoda parametryczna opiera się na założeniu normalności i liniowości, przez co niedoszacowuje ryzyka dla rozkładów z grubymi ogonami oraz instrumentów nieliniowych jak opcje. Pozostałe opisy są błędne — metoda korzysta z macierzy kowariancji i obsługuje portfele."}, {"q": "Portfel składa się z dwóch pozycji o jednodniowych VaR równych 3 mln zł i 4 mln zł. Jak ich korelacja wpływa na VaR całego portfela?", "options": ["Przy korelacji mniejszej niż 1 VaR portfela jest mniejszy niż 7 mln zł dzięki efektowi dywersyfikacji", "VaR portfela zawsze równa się sumie, czyli 7 mln zł, niezależnie od korelacji", "VaR portfela zawsze równa się różnicy, czyli 1 mln zł", "VaR portfela jest większy niż 7 mln zł, bo ryzyka się kumulują wykładniczo"], "correct": 0, "explain": "VaR portfela = √(VaR₁² + VaR₂² + 2·ρ·VaR₁·VaR₂). Suma 7 mln zł zachodzi tylko przy ρ = 1; dla ρ mniejszego niż 1 efekt dywersyfikacji obniża VaR (np. dla ρ = 0 wynosi 5 mln zł)."}], "t2": [{"q": "Bank ocenia kredyt o następujących parametrach: prawdopodobieństwo niewypłacalności PD = 4%, strata w przypadku niewykonania zobowiązania LGD = 50%, ekspozycja w momencie default EAD = 200 000 zł. Ile wynosi strata oczekiwana (EL)?", "options": ["4 000 zł", "8 000 zł", "40 000 zł", "2 000 zł"], "correct": 0, "explain": "EL = PD · LGD · EAD = 0,04 · 0,50 · 200 000 = 4 000 zł."}, {"q": "Co wyraża parametr LGD (Loss Given Default) w modelu ryzyka kredytowego?", "options": ["Prawdopodobieństwo, że kredytobiorca nie spłaci zobowiązania w ciągu roku", "Część ekspozycji, którą bank realnie traci (procentowo), gdy dojdzie do niewykonania zobowiązania", "Wartość ekspozycji w momencie wystąpienia niewykonania zobowiązania", "Roczny koszt finansowania kredytu ponoszony przez bank"], "correct": 1, "explain": "LGD to udział straty w ekspozycji w przypadku defaultu, czyli (1 − stopa odzysku); pozostałe opisy dotyczą PD i EAD."}, {"q": "Stopa odzysku (recovery rate) z zabezpieczenia kredytu wynosi 70%. Jaka jest wartość LGD przy założeniu braku innych kosztów windykacji?", "options": ["70%", "130%", "30%", "0,7%"], "correct": 2, "explain": "LGD = 1 − stopa odzysku = 1 − 0,70 = 0,30, czyli 30%."}, {"q": "Która z poniższych sytuacji jest przykładem negatywnej selekcji (adverse selection) wynikającej z asymetrii informacji na rynku kredytowym?", "options": ["Kredytobiorca po otrzymaniu kredytu przeznacza środki na bardziej ryzykowną inwestycję niż deklarował", "Podniesienie oprocentowania odstrasza klientów o niskim ryzyku, a przyciąga głównie najbardziej ryzykownych wnioskodawców", "Bank wymaga zabezpieczenia hipotecznego w celu obniżenia LGD", "Bank monitoruje rachunek kredytobiorcy w trakcie trwania umowy"], "correct": 1, "explain": "Negatywna selekcja występuje PRZED zawarciem umowy: wyższa cena kredytu wypycha dobrych klientów, zostawiając ryzykownych; opcja o zmianie zachowania PO udzieleniu kredytu to pokusa nadużycia (moral hazard)."}, {"q": "Dlaczego banki stosują zabezpieczenia (np. hipotekę, zastaw) przy udzielaniu kredytów?", "options": ["Aby obniżyć przede wszystkim parametr PD danego kredytobiorcy", "Aby ograniczyć stratę przy niewykonaniu zobowiązania poprzez obniżenie LGD", "Aby zwiększyć ekspozycję EAD kredytu", "Aby całkowicie wyeliminować ryzyko kredytowe z transakcji"], "correct": 1, "explain": "Zabezpieczenie zmniejsza stratę w razie defaultu (podnosi odzysk), więc obniża LGD, a nie PD; ryzyka nie eliminuje całkowicie (np. spadek wartości zabezpieczenia)."}, {"q": "Scoring kredytowy to:", "options": ["Metoda statystyczna przypisująca wnioskodawcy punktową ocenę szacującą prawdopodobieństwo terminowej spłaty", "Wymóg kapitałowy nakładany na bank przez nadzór finansowy", "Wartość rynkowa zabezpieczenia przyjętego pod kredyt", "Procedura egzekucji należności od niewypłacalnego dłużnika"], "correct": 0, "explain": "Scoring to ilościowa, statystyczna ocena zdolności/skłonności do spłaty na podstawie cech wnioskodawcy; pozostałe odpowiedzi dotyczą innych pojęć (wymogi kapitałowe, wycena zabezpieczeń, windykacja)."}, {"q": "Dwa kredyty mają tę samą ekspozycję EAD = 100 000 zł. Kredyt A: PD = 2%, LGD = 60%. Kredyt B: PD = 5%, LGD = 20%. Który ma wyższą stratę oczekiwaną i ile ona wynosi?", "options": ["Kredyt A, EL = 1 200 zł", "Kredyt B, EL = 1 000 zł", "Oba mają taką samą EL = 1 200 zł", "Kredyt A, EL = 6 000 zł"], "correct": 0, "explain": "EL_A = 0,02 · 0,60 · 100 000 = 1 200 zł; EL_B = 0,05 · 0,20 · 100 000 = 1 000 zł. Wyższą stratę oczekiwaną ma kredyt A."}, {"q": "Zdolność kredytowa w rozumieniu Prawa bankowego to:", "options": ["Wartość majątku, który kredytobiorca może przeznaczyć na zabezpieczenie kredytu", "Zdolność do spłaty zaciągniętego kredytu wraz z odsetkami w terminach określonych w umowie", "Maksymalna kwota, jaką bank może pożyczyć jednemu klientowi zgodnie z limitem koncentracji", "Historia terminowości spłat zapisana w bazie BIK"], "correct": 1, "explain": "Zdolność kredytowa to zdolność do spłaty kapitału wraz z odsetkami w umownych terminach; pozostałe opcje opisują zabezpieczenie, limit koncentracji i historię kredytową, które są tylko elementami oceny lub odrębnymi pojęciami."}], "t3": [{"q": "Zgodnie z ustawą o rachunkowości jednostka bilansuje aktywa i pasywa, natomiast nadrzędną kategorią porządkującą ujmowanie i wycenę w MSR/MSSF jest:", "options": ["Ostrożna wycena oparta wyłącznie na koszcie historycznym", "Definicja składnika aktywów/zobowiązań i koncepcja przeniesienia ryzyka oraz korzyści (podejście bilansowe oparte na wartości)", "Zasada współmierności przychodów i kosztów jako kryterium nadrzędne nad definicją aktywów", "Zasada memoriału stosowana wyłącznie do przychodów odsetkowych"], "correct": 1, "explain": "MSSF opierają się na podejściu bilansowym i Założeniach Koncepcyjnych — punktem wyjścia jest definicja aktywu/zobowiązania oraz przeniesienie ryzyka i korzyści, a nie sama współmierność czy wyłącznie koszt historyczny."}, {"q": "Bank klasyfikuje instrument dłużny zgodnie z MSSF 9. Aby wyceniać go w zamortyzowanym koszcie, muszą być spełnione łącznie dwa warunki. Który zestaw jest poprawny?", "options": ["Model biznesowy = utrzymanie dla pozyskania przepływów umownych ORAZ przepływy spełniają test SPPI (wyłącznie kapitał i odsetki)", "Model biznesowy = obrót handlowy ORAZ przepływy zmienne zależne od wyniku", "Klasyfikacja jako dostępne do sprzedaży ORAZ wycena do wartości godziwej przez kapitał", "Brak wbudowanych instrumentów pochodnych ORAZ wycena do wartości godziwej przez wynik"], "correct": 0, "explain": "MSSF 9 wymaga jednocześnie modelu biznesowego 'hold to collect' oraz spełnienia testu SPPI; tylko wtedy instrument dłużny wycenia się w zamortyzowanym koszcie."}, {"q": "Według MSSF 9 model utraty wartości dla należności kredytowych opiera się na:", "options": ["Stratach już poniesionych (incurred loss) ujmowanych dopiero po zdarzeniu niewykonania", "Oczekiwanych stratach kredytowych (ECL) szacowanych w przód, z podziałem na 3 etapy (12-miesięczne lub w całym okresie życia)", "Stałym odpisie ryczałtowym równym 1% wartości portfela", "Odpisie ujmowanym wyłącznie po formalnym wypowiedzeniu umowy kredytowej"], "correct": 1, "explain": "MSSF 9 zastąpił model strat poniesionych modelem oczekiwanych strat kredytowych (ECL) — odpis tworzy się z wyprzedzeniem, a stopień zależy od etapu (Stage 1/2/3)."}, {"q": "Bank udzielił kredytu o wartości nominalnej 100 000 zł i pobrał z góry prowizję (opłatę) 2 000 zł stanowiącą integralną część stopy procentowej. Jak ujmowana jest ta prowizja w wycenie zamortyzowanym kosztem (efektywna stopa procentowa)?", "options": ["W całości jako przychód w momencie wypłaty kredytu", "Rozliczana w czasie przez korektę efektywnej stopy procentowej przez okres życia kredytu", "Pomniejsza kapitał własny banku w dacie udzielenia", "Ujmowana jako rezerwa na ryzyko kredytowe do czasu spłaty"], "correct": 1, "explain": "Opłaty będące integralną częścią efektywnej stopy procentowej wchodzą do kalkulacji EIR i są rozliczane w czasie przez cały okres życia instrumentu, a nie ujmowane jednorazowo."}, {"q": "Która z poniższych pozycji jest klasyfikowana jako REZERWA (a nie odpis aktualizujący / korekta wartości aktywu) w bilansie banku?", "options": ["Odpis na oczekiwane straty kredytowe od portfela kredytów", "Korekta wartości udziałów z tytułu utraty wartości", "Rezerwa na sprawy sporne (pozew sądowy) o niepewnej kwocie i terminie", "Dyskonto od nabytych dłużnych papierów wartościowych"], "correct": 2, "explain": "Rezerwa to zobowiązanie o niepewnej kwocie lub terminie (np. spór sądowy). Odpisy na ECL czy utratę wartości to korekty wartości aktywów, a dyskonto to element wyceny — nie są rezerwami w pasywach."}, {"q": "Bank posiada obligację skarbową utrzymywaną w modelu 'hold to collect and sell' (zbieranie przepływów oraz sprzedaż). Zgodnie z MSSF 9 wycena następuje:", "options": ["W zamortyzowanym koszcie, a różnice w wyniku finansowym", "W wartości godziwej przez pozostałe całkowite dochody (FVOCI), z odsetkami liczonymi metodą EIR w wyniku", "W wartości godziwej przez wynik finansowy (FVTPL) bez wyjątków", "Wyłącznie w cenie nabycia bez aktualizacji do końca okresu utrzymywania"], "correct": 1, "explain": "Model mieszany 'hold to collect and sell' przy spełnieniu SPPI prowadzi do wyceny FVOCI: zmiany wartości godziwej idą przez kapitał (OCI), a odsetki/EIR i ECL przez wynik."}, {"q": "Czym różni się ujęcie utraty wartości w ustawie o rachunkowości od MSSF 9 w odniesieniu do należności kredytowych?", "options": ["Ustawa wymaga modelu oczekiwanych strat, a MSSF 9 modelu strat poniesionych", "Ustawa o rachunkowości opiera się głównie na odpisach przy wystąpieniu przesłanek utraty wartości (zbliżone do strat poniesionych), a MSSF 9 wymaga proaktywnych odpisów ECL", "Obie regulacje nakazują identyczny 3-etapowy model ECL", "Ustawa zakazuje tworzenia jakichkolwiek odpisów aktualizujących należności"], "correct": 1, "explain": "Polska ustawa (poza bankami stosującymi rozporządzenia/MSSF) tworzy odpisy gdy pojawią się przesłanki utraty wartości (model zbliżony do strat poniesionych), podczas gdy MSSF 9 wymaga prospektywnych odpisów ECL już od momentu ujęcia."}, {"q": "Bank wycenia kredyt zamortyzowanym kosztem. Wartość bilansowa brutto wynosi 500 000 zł, a oszacowany odpis ECL to 30 000 zł. Jaka jest wartość bilansowa NETTO kredytu wykazywana w aktywach?", "options": ["530 000 zł", "500 000 zł", "470 000 zł", "30 000 zł"], "correct": 2, "explain": "Wartość netto = wartość brutto minus odpis ECL = 500 000 − 30 000 = 470 000 zł; odpis pomniejsza wartość aktywu wykazywanego w bilansie."}]};
